,p_item_plug_id=>wwv_flow_imp.id(273500684615190036)
,p_display_as=>'NATIVE_HIDDEN'
,p_attributes=>wwv_flow_t_plugin_attributes(wwv_flow_t_varchar2(
  'value_protected', 'Y')).to_clob
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(270379725538773442)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CREATE_JOB'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_job_id number;',
'begin',
'  insert into demo_sync_job (created_by, status, last_message)',
'  values (:APP_USER, ''CREATED'', ''Job created'')',
'  returning job_id into l_job_id;',
'',
'  :P1_JOB_ID := l_job_id;',
'',
'  insert into demo_sync_job_item (job_id, doc_id, status)',
'  select l_job_id, doc_id, ''PENDING''',
'    from demo_doc;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(270379553183773440)
,p_internal_uid=>270379725538773442
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(270379938625773444)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_EXECUTION_CHAIN'
,p_process_name=>'SYNC_CHAIN'
,p_attribute_01=>'Y'
,p_attribute_02=>'N'
,p_attribute_04=>'IGNORE'
,p_attribute_09=>'N'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_internal_uid=>270379938625773444
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(270380027461773445)
,p_process_sequence=>10
,p_parent_process_id=>wwv_flow_imp.id(270379938625773444)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CHAIN_INIT'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_exec  apex_background_process.t_execution;',
'  l_total number;',
'begin',
'  l_exec := apex_background_process.get_current_execution; -- id, state, sofar, totalwork... :contentReference[oaicite:5]{index=5}',
'',
'  select count(*)',
'    into l_total',
'    from demo_sync_job_item',
'   where job_id = :P1_JOB_ID;',
'',
'  update demo_sync_job',
'     set started_at   = systimestamp,',
'         status       = ''RUNNING'',',
'         execution_id = l_exec.id,',
'         state        = l_exec.state,',
'         sofar        = 0,',
'         totalwork    = l_total,',
'         last_message = ''Starting...''',
'   where job_id = :P1_JOB_ID;',
'',
'  apex_background_process.set_progress(p_totalwork => l_total, p_sofar => 0);',
'  apex_background_process.set_status(''Starting...'');',
'',
'  commit;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>270380027461773445
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(270380194186773446)
,p_process_sequence=>20
,p_parent_process_id=>wwv_flow_imp.id(270379938625773444)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CHAIN_SEND_DOCS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_total number;',
'  l_done  number := 0;',
'',
'  -- centiseconds: 1 = 0.01s | 25 = 0.25s',
'  procedure simulate_work(p_centiseconds number) is',
'    l_start number := dbms_utility.get_time;',
'  begin',
'    while (dbms_utility.get_time - l_start) < p_centiseconds loop',
'      null;',
'    end loop;',
'  end;',
'begin',
'  select totalwork',
'    into l_total',
'    from demo_sync_job',
'   where job_id = :P1_JOB_ID;',
'',
'  for r in (',
'    select i.job_item_id,',
'           d.doc_id,',
'           d.doc_name,',
'           d.size_kb',
'      from demo_sync_job_item i',
'      join demo_doc d on d.doc_id = i.doc_id',
'     where i.job_id = :P1_JOB_ID',
'       and i.status = ''PENDING''',
'     order by d.doc_id',
'  ) loop',
'    begin',
'      update demo_sync_job_item',
'         set status     = ''RUNNING'',',
'             started_at = systimestamp',
'       where job_item_id = r.job_item_id;',
'',
unistr('      -- Simula \201Cupload/post\201D (0.10s a ~0.35s, variando com size_kb)'),
'      simulate_work(10 + least(r.size_kb, 5000) / 20);',
'',
'      -- Simula erro em alguns casos (pra demo)',
'      if mod(r.doc_id, 17) = 0 then',
'        raise_application_error(-20001, ''Simulated error for demo'');',
'      end if;',
'',
'      update demo_sync_job_item',
'         set status   = ''DONE'',',
'             ended_at = systimestamp',
'       where job_item_id = r.job_item_id;',
'',
'    exception',
'      when others then',
'        declare',
'          l_err varchar2(4000);',
'        begin',
unistr('          -- SQLERRM \00E9 PL/SQL (use numa vari\00E1vel e depois persista)'),
'          l_err := substr(sqlerrm, 1, 4000);',
'',
'          update demo_sync_job_item',
'             set status    = ''FAILED'',',
'                 ended_at  = systimestamp,',
'                 error_msg = l_err',
'           where job_item_id = r.job_item_id;',
'        end;',
'    end;',
'',
'    l_done := l_done + 1;',
'',
'    update demo_sync_job',
'       set sofar        = l_done,',
'           last_message = ''Sending '' || l_done || '' of '' || l_total || '' - '' || r.doc_name',
'     where job_id = :P1_JOB_ID;',
'',
'    apex_background_process.set_progress(p_totalwork => l_total, p_sofar => l_done);',
'    apex_background_process.set_status(''Sending '' || l_done || '' of '' || l_total || '' - '' || r.doc_name);',
'',
unistr('    commit; -- importante pro monitor ver \201Cao vivo\201D'),
'  end loop;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>270380194186773446
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(270380246295773447)
,p_process_sequence=>30
,p_parent_process_id=>wwv_flow_imp.id(270379938625773444)
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'CHAIN_FINALIZE'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_failed number;',
'  l_total  number;',
'begin',
'  select count(*) into l_failed',
'    from demo_sync_job_item',
'   where job_id = :P1_JOB_ID',
'     and status = ''FAILED'';',
'',
'  select totalwork into l_total',
'    from demo_sync_job',
'   where job_id = :P1_JOB_ID;',
'',
'  update demo_sync_job',
'     set ended_at = systimestamp,',
'         status   = case when l_failed > 0 then ''WARN'' else ''SUCCESS'' end,',
'         last_message = case when l_failed > 0 then ''Finished with errors'' else ''Finished successfully'' end,',
'         sofar    = l_total',
'   where job_id = :P1_JOB_ID;',
'',
'  apex_background_process.set_progress(p_totalwork => l_total, p_sofar => l_total);',
'  apex_background_process.set_status(case when l_failed > 0 then ''Finished with errors'' else ''Finished successfully'' end);',
'',
'  commit;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>270380246295773447
);
end;
/
